type Func = (...args: ["a", number] | ["b", string]) => void;

const f1: Func = (kind, payload) => {
  if (kind === "a") {
    // \u4ECD\u7136\u662F string | number
    payload.toFixed();
  }
  if (kind === "b") {
    // \u4ECD\u7136\u662F string | number
    payload.toUpperCase();
  }
};
