`,paraId:14,tocIndex:2},{value:"JSON.stringify \u7684\u5B8C\u6574\u8BED\u6CD5\u662F\uFF1A",paraId:15,tocIndex:2},{value:"let json = JSON.stringify(value[, replacer, space])",paraId:15,tocIndex:2},{value:`// \u53BB\u9664\u5BFC\u81F4\u5FAA\u73AF\u5F15\u7528\u7684 room.occupiedBy
let room = {
  number: 23,
}

let meetup = {
  title: 'Conference',
  participants: [{ name: 'John' }, { name: 'Alice' }],
  place: room, // meetup \u5F15\u7528\u4E86 room
}

room.occupiedBy = meetup // room \u5F15\u7528\u4E86 meetup

alert(
  JSON.stringify(meetup, function replacer(key, value) {
    return key == 'occupiedBy' ? undefined : value
  }),
)

/* key:value pairs that come to replacer:
:             [object Object]
title:        Conference
participants: [object Object],[object Object]
0:            [object Object]
name:         John
1:            [object Object]
name:         Alice
place:        [object Object]
number:       23
occupiedBy: [object Object]
*/
