class AParent {
  constructor() {
    console.log(new.target)
  }
}

// \u65E0\u7EE7\u627F
const aParent = new AParent()
// [class AParent]

// \u6709\u7EE7\u627F
class AChild extends AParent {}
const aChild = new AChild()
// [class AChild extends AParent]
`,paraId:25,tocIndex:4},{value:"ES6 \u5141\u8BB8\u7EE7\u627F\u539F\u751F\u6784\u9020\u51FD\u6570\u5B9A\u4E49\u5B50\u7C7B\u3002",paraId:26,tocIndex:5},{value:"\u539F\u751F\u6784\u9020\u51FD\u6570\u662F\u6307\u8BED\u8A00\u5185\u7F6E\u7684\u6784\u9020\u51FD\u6570\uFF0C\u901A\u5E38\u7528\u6765\u751F\u6210\u6570\u636E\u7ED3\u6784\u3002ECMAScript \u7684\u539F\u751F\u6784\u9020\u51FD\u6570\u5927\u81F4\u6709\u4E0B\u9762\u8FD9\u4E9B\u3002",paraId:27,tocIndex:5},{value:"Boolean()",paraId:28,tocIndex:5},{value:"Number()",paraId:28,tocIndex:5},{value:"String()",paraId:28,tocIndex:5},{value:"Array()",paraId:28,tocIndex:5},{value:"Date()",paraId:28,tocIndex:5},{value:"Function()",paraId:28,tocIndex:5},{value:"RegExp()",paraId:28,tocIndex:5},{value:"Error()",paraId:28,tocIndex:5},{value:"Object()",paraId:28,tocIndex:5},{value:`// \u7B2C\u4E00\u7248
function Super() {
  this.super_param = [1, 2, 3]
}
Super.prototype.getSuperParam = function () {
  return this.super_param
}
function Sub() {
  this.sub_param = true
}
Sub.prototype = new Super()
Sub.prototype.getSubParam = function () {
  return this.sub_param
}
var instance1 = new Sub()
var instance2 = new Sub()
instance1.super_param.push(4)

console.log(instance1.super_param) // [1, 2, 3, 4]
console.log(instance2.super_param) // [1, 2, 3, 4]

// \u7F3A\u70B91\uFF1A\u5F15\u7528\u7C7B\u578B\u5C5E\u6027\u5171\u4EAB
// \u7F3A\u70B92\uFF1ASub.prototype \u91CD\u5199\u4E22\u5931 constructor
`,paraId:29,tocIndex:7},{value:`// \u7B2C\u4E8C\u7248
function Super() {
  this.super_param = [1, 2, 3]
}
Super.prototype.getSuperParam = function () {
  return this.super_param
}
function Sub() {
  Super.call(this)
  this.sub_param = true
}
Sub.prototype = new Super()
Sub.prototype.constructor = Sub
Sub.prototype.getSubParam = function () {
  return this.sub_param
}
var instance1 = new Sub()
var instance2 = new Sub()
instance1.super_param.push(4)

console.log(instance1.super_param) // [1, 2, 3, 4]
console.log(instance2.super_param) // [1, 2, 3]
console.log(Sub.prototype.constructor === Sub) // true

// \u7F3A\u70B9\uFF1ASuper() \u8C03\u7528\u4E86\u4E24\u6B21
`,paraId:30,tocIndex:8},{value:`// \u7B2C\u4E09\u7248
function Super() {
  this.super_param = [1, 2, 3]
}
Super.prototype.getSuperParam = function () {
  return this.super_param
}
function Sub() {
  Super.call(this)
  this.sub_param = true
}
// Sub.prototype = Object.create(Super.prototype) // \u91CD\u5199\u4E86 Sub.prototype === {}
// Sub.prototype.constructor = Sub
// \u4E0B\u9762\u76F8\u5F53\u4E8E\u4E0A\u9762\u4E24\u884C
Object.setPrototypeOf(Sub.prototype, Super.prototype) // \u8BBE\u7F6E\u539F\u578B\u94FE\u4F1A\u8986\u76D6\u9ED8\u8BA4\u7684\u539F\u578B\u94FE\u5173\u7CFB

Sub.prototype.getSubParam = function () {
  return this.sub_param
}
var instance1 = new Sub()
var instance2 = new Sub()
instance1.super_param.push(4)

console.log(instance1.super_param) // [1, 2, 3, 4]
console.log(instance2.super_param) // [1, 2, 3]
console.log(Sub.prototype.constructor === Sub) // true
